#include <bits/stdc++.h>
using namespace std;
char a[20][20];
int v,t;
int main(){
	int n,m,answer=0;
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		for(int j=1;j<=m;j++){
			cin>>a[i][j];
		}
	}
	for(int i=1;i<=n;i++){
		for(int j=1;j<=m;j++){
			for(int k=i;k<=n;k++){
				for(int l=j;l<=m;l++){
					v=0,t=0;
					for(int o=i;o<=k;o++){
						for(int p=j;p<=l;p++){
							if(a[o][p]=='1'){
								v++;
							}else{
								t++;
							}
						}
					}
					if(v==t){
						answer=max(answer,(k-i+1)*(l-j+1));
					}
				}
			}
		}
	}
	cout<<answer;
	return 0;
}
